function calculate({
  partyAInitialStance,
  partyBInitialStance,
  mutualInterestAlignment,
  relativePowerDifferential,
  trustAndTransparencyLevel,
  communicationEffectiveness,
  willingnessToCompromiseA,
  willingnessToCompromiseB,
  externalStakeholderInfluence
}) {
  // Normalize inputs to a 0-1 scale where appropriate for calculations
  const initialStanceA_norm = partyAInitialStance / 10;
  const initialStanceB_norm = partyBInitialStance / 10;
  const mutualInterest_norm = mutualInterestAlignment / 100;
  const powerDifferential_norm = relativePowerDifferential / 10;
  const trust_norm = trustAndTransparencyLevel / 10;
  const communication_norm = communicationEffectiveness / 10;
  const compromiseA_norm = willingnessToCompromiseA / 10;
  const compromiseB_norm = willingnessToCompromiseB / 10;
  const externalInfluence_norm = externalStakeholderInfluence / 10;

  // Step 1: Calculate Cooperation Potential
  // High mutual interest, trust, communication, and willingness to compromise boost cooperation
  let cooperationPotential = (
    mutualInterest_norm * 0.30 +
    trust_norm * 0.25 +
    communication_norm * 0.20 +
    (compromiseA_norm + compromiseB_norm) / 2 * 0.25
  );
  cooperationPotential = Math.max(0, Math.min(1, cooperationPotential)); // Cap between 0 and 1

  // Step 2: Calculate Conflict & Difficulty Factors
  // High initial stances, power imbalance, and external influence increase conflict/difficulty
  // Low trust/communication can also contribute to difficulty
  let conflictDifficulty = (
    ((initialStanceA_norm + initialStanceB_norm) / 2) * 0.25 +
    powerDifferential_norm * 0.20 +
    (1 - trust_norm) * 0.15 + // Lack of trust adds difficulty
    (1 - communication_norm) * 0.10 + // Poor communication adds difficulty
    (1 - mutualInterest_norm) * 0.15 + // Lack of common ground adds difficulty
    externalInfluence_norm * 0.15 // External pressures add difficulty
  );
  conflictDifficulty = Math.max(0, Math.min(1, conflictDifficulty)); // Cap between 0 and 1

  // Step 3: Calculate Efficiency Factor
  // High communication, trust, and willingness to compromise improve efficiency. Lower initial stances help.
  let efficiencyFactor = (
    communication_norm * 0.35 +
    trust_norm * 0.25 +
    (compromiseA_norm + compromiseB_norm) / 2 * 0.20 -
    ((initialStanceA_norm + initialStanceB_norm) / 2) * 0.10 -
    externalInfluence_norm * 0.10 // External influence can reduce efficiency
  );
  efficiencyFactor = Math.max(0, Math.min(1, efficiencyFactor)); // Cap between 0 and 1

  // Step 4: Derive Outputs from Factors

  // Negotiation Success Probability
  // High cooperation, low conflict/difficulty lead to higher success probability
  let negotiationSuccessProbability = (cooperationPotential * 0.7) + ((1 - conflictDifficulty) * 0.3);
  negotiationSuccessProbability = Math.max(0.05, Math.min(0.95, negotiationSuccessProbability)); // Hard cap between 5% and 95%
  negotiationSuccessProbability = negotiationSuccessProbability * 100; // Convert to percentage

  // Mutual Gain Potential
  // Strongly tied to mutual interest, cooperation, and overall success probability
  let mutualGainPotential = mutualInterest_norm * cooperationPotential * 0.8 + (negotiationSuccessProbability / 100) * 0.2;
  mutualGainPotential = Math.max(0, Math.min(1, mutualGainPotential));
  mutualGainPotential = mutualGainPotential * 100; // Convert to percentage

  // Stability of Agreement (Long-term)
  // High trust, communication, and low power imbalance contribute to stability
  let stabilityOfAgreement = (trust_norm * 0.3) + (communication_norm * 0.2) + ((1 - powerDifferential_norm) * 0.2) + (cooperationPotential * 0.3);
  stabilityOfAgreement = Math.max(0, Math.min(1, stabilityOfAgreement));
  stabilityOfAgreement = stabilityOfAgreement * 100; // Convert to percentage

  // Risk of Negotiation Breakdown
  // Inverse of success probability, but also boosted by conflict/difficulty
  let riskOfBreakdown = (conflictDifficulty * 0.6) + ((1 - cooperationPotential) * 0.4);
  riskOfBreakdown = Math.max(0.05, Math.min(0.95, riskOfBreakdown)); // Hard cap between 5% and 95%
  riskOfBreakdown = riskOfBreakdown * 100; // Convert to percentage

  // Ensure riskOfBreakdown + negotiationSuccessProbability approx 100% (within reasonable bounds)
  // We prioritize success probability, so adjust breakdown accordingly to sum to 100% (or very close)
  riskOfBreakdown = 100 - negotiationSuccessProbability;
  riskOfBreakdown = Math.max(5, Math.min(95, riskOfBreakdown)); // Re-cap after adjustment

  // Estimated Negotiation Phases (Rounds)
  // Higher conflict/difficulty and lower efficiency increase phases
  // Base phases start at 3, add more based on complexity.
  let estimatedNegotiationPhases = 3; // Minimum viable phases
  estimatedNegotiationPhases += conflictDifficulty * 7; // Up to 7 more phases for high conflict
  estimatedNegotiationPhases += (1 - efficiencyFactor) * 5; // Up to 5 more phases for low efficiency
  estimatedNegotiationPhases += (1 - mutualInterest_norm) * 3; // Up to 3 more for very low mutual interest
  estimatedNegotiationPhases += powerDifferential_norm * 2; // Up to 2 more for high power differential
  estimatedNegotiationPhases = Math.round(Math.max(1, Math.min(20, estimatedNegotiationPhases))); // Cap between 1 and 20

  return {
    negotiationSuccessProbability: negotiationSuccessProbability,
    mutualGainPotential: mutualGainPotential,
    stabilityOfAgreement: stabilityOfAgreement,
    riskOfBreakdown: riskOfBreakdown,
    estimatedNegotiationPhases: estimatedNegotiationPhases
  };
}
